import { useState } from "react";
import { toast } from "sonner";
import { Button, Toaster } from "@repo/components";

const directions = ["ltr", "rtl", "auto"];

export default function SonnerDirection() {
    const [dir, setDir] = useState("auto");

    return (
        <div className="flex flex-col items-center gap-3">
            <Toaster dir={dir} />
            <div className="flex flex-wrap justify-center gap-2">
                {directions.map((d) => (
                    <Button
                        key={d}
                        variant={dir === d ? "default" : "outline"}
                        onClick={() => { setDir(d); toast(`Direction: ${d}`); }}
                    >
                        {d.toUpperCase()}
                    </Button>
                ))}
            </div>
        </div>
    );
}

import { useState } from "react";
import { toast } from "sonner";
import { Button, Toaster } from "@repo/components";

const counts = [1, 3, 5, 9];

export default function SonnerVisibleToasts() {
    const [visibleToasts, setVisibleToasts] = useState(3);

    return (
        <div className="flex flex-col items-center gap-3">
            <Toaster visibleToasts={visibleToasts} />
            <p className="text-sm text-muted-foreground">
                Max visible: <span className="font-medium text-foreground">{visibleToasts}</span>
            </p>
            <div className="flex flex-wrap justify-center gap-2">
                {counts.map((n) => (
                    <Button key={n} variant={visibleToasts === n ? "default" : "outline"} onClick={() => setVisibleToasts(n)}>{n}</Button>
                ))}
            </div>
            <Button variant="outline" onClick={() => toast(`Toast at ${new Date().toLocaleTimeString()}`)}>Add Toast</Button>
        </div>
    );
}

import { useState } from "react";
import { toast } from "sonner";
import { Button, Toaster } from "@repo/components";

const gaps = [4, 8, 14, 24];

export default function SonnerGap() {
    const [gap, setGap] = useState(14);

    return (
        <div className="flex flex-col items-center gap-3">
            <Toaster gap={gap} />
            <p className="text-sm text-muted-foreground">
                Gap: <span className="font-medium text-foreground">{gap}px</span>
            </p>
            <div className="flex flex-wrap justify-center gap-2">
                {gaps.map((g) => (
                    <Button key={g} variant={gap === g ? "default" : "outline"} onClick={() => setGap(g)}>{g}px</Button>
                ))}
            </div>
            <Button variant="outline" onClick={() => toast(`Toast — gap is ${gap}px`)}>Add Toast</Button>
        </div>
    );
}
